#include <iostream>

int main()
{
    int n = 0;
    std::cin >> n;
    std::cout << "start: " << n << '\n';

    int postResult = n++;
    std::cout << "post-inc result: " << postResult << '\n';
    std::cout << "after post-inc: " << n << '\n';

    int preResult = --n;
    std::cout << "pre-dec result: " << preResult << '\n';
    std::cout << "after pre-dec: " << n << '\n';

    return 0;
}

