solution_code:
#include <iostream>

int nextValue(int x)
{
    return ++x;
}

int prevValue(int x)
{
    return --x;
}

int main()
{
    int n = 0;
    std::cin >> n;
    std::cout << "next: " << nextValue(n) << '\n';
    std::cout << "prev: " << prevValue(n) << '\n';
    return 0;
}
